// MathBox +esm 与 Threestrap root 各持有 Bootstrap；合并已注册插件表后再初始化
const el = document.getElementById('mathbox'); el.style.height = '480px'; el.textContent = 'Loading 3D plot…';
const css = Object.assign(document.createElement('link'), { rel: 'stylesheet', href: 'https://cdn.jsdelivr.net/npm/mathbox@2.3.2-rc1/build/mathbox.css' }); document.head.appendChild(css);
const [{ mathBox }, { Bootstrap }, { OrbitControls }, { Bootstrap: SourceBootstrap }] = await Promise.all([
  import('https://cdn.jsdelivr.net/npm/mathbox@2.3.2-rc1/+esm'),
  import('https://cdn.jsdelivr.net/npm/threestrap@0.5.1/+esm'),
  import('https://cdn.jsdelivr.net/npm/three@0.148.0/examples/jsm/controls/OrbitControls.js/+esm'),
  import('https://cdn.jsdelivr.net/npm/threestrap@0.5.1/src/bootstrap.js/+esm')
]);
el.textContent = '';
const root = mathBox({ element: el, plugindb: { ...Bootstrap.Plugins, ...SourceBootstrap.Plugins }, aliasdb: Bootstrap.Aliases, controls: { klass: OrbitControls } });
const view = root.cartesian({ range: data.range ?? [[-3,3],[-2,2],[-2,2]], scale: data.scale ?? [1,1,1] });
for (const axis of data.axes ?? [1,2,3]) view.axis({ axis });
if (data.curve) { const f = Function('x', 'return (' + data.curve.expression + ')'); view.interval({ width: data.curve.samples ?? 128, channels: 3, range: data.curve.domain ?? (data.range?.[0] ?? [-3,3]), expr: (emit, x) => emit(x, f(x), 0) }).line({ width: data.curve.width ?? 4, color: data.curve.color ?? 0x3090ff }); }

